SELECT count(*) FROM movie_keyword, title, keyword, cast_info, kind_type, movie_companies, char_name, name, aka_name WHERE movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id;